func solve(weight: Array<Int64>) -> Int64 {
    var n = weight.count
    var result = 0
    var i = 0

    while i < n {
        var maxWeight = Int64(-1)
        var j = i

        // Find the longest subarray starting at i that is a balanced shipment
        while j < n {
            maxWeight = max(maxWeight, weight[j])
            if weight[j] < maxWeight {
                // Found a balanced shipment from i to j
                result += 1
                i = j + 1
                break
            }
            j += 1
        }

        // If no balanced shipment found starting at i, move to next position
        if j == n {
            i += 1
        }
    }

    return Int64(result)
}
